WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/18.0/connection.js")}
{!REQUIRESCRIPT("/soap/ajax/18.0/apex.js")}

var StageValue= "{!Opportunity.StageName}";
var RenewalRequired = "{!Opportunity.Renewal_Required_INF__c}";
var profile = "{!$Profile.Name}";
if ("{!Opportunity.AccountId}" == '0013000001DIl1y'&& "{!Opportunity.Contract_Request__c}"=='')
{
alert("All orders to be sent to Contracts for review before processing");
}

else if(RenewalRequired == null || RenewalRequired=='')
{
alert("Submission is rejected due to Renewal Required field empty or null");
}
else if (StageValue == 'Stage 6 - Implement (Closed)' || StageValue == 'Closed Won'|| StageValue == 'Closed Lost' || profile == 'Informatics Operations')
{
alert("Invalid Operation");
}
else if(profile != 'Informatics Operations')
{
sforce.connection.query("SELECT Id,Name,Order_Processing_Status_INF__c,StageName FROM Opportunity where Id= '{!Opportunity.Id}'",{onSuccess: handleSuccess,onFailure: handleFailure});
function handleSuccess(queryresult)
{
try
{
records = queryresult.getArray("records");
records[0].Id='{!Opportunity.Id}';
records[0].StageName='Stage 6 - Implement (Closed)';
records[0].Order_Processing_Status_INF__c='Submitted';
var uprec = sforce.connection.update(records);
if (uprec[0].getBoolean("success"))
{
window.location.reload();
}
else
{
alert(uprec[0].errors.message);
}
}
catch(error)
{
alert(error);
}
}
function handleFailure(error)
{
alert(error);
}
}
